mapper.sql:
SELECT ASRT.CTKEY , CT.CTNM , ASRT.OWKEY , OW.OWNM , ASRT.ASRTMASICKEY , IC.ICNM AS ASRTMASICNM , SUM(ASRT.QTY) AS QTY , MAX(ASRT.INSERTDATE) AS INSERTDATE , MAX(ASRT.INSERTURKEY) AS INSERTURKEY , MAX(ASRT.UPDATEDATE) AS UPDATEDATE , MAX(ASRT.UPDATEURKEY) AS UPDATEURKEY FROM TWORK_MST_ASRT ASRT INNER JOIN TWORK_MST_CT CT ON CT.CTKEY = ASRT.CTKEY INNER JOIN TWORK_MST_OW OW ON OW.OWKEY = ASRT.OWKEY INNER JOIN TWORK_MST_IC IC ON IC.CTKEY = ASRT.CTKEY AND IC.OWKEY = ASRT.OWKEY AND IC.ICKEY = ASRT.ASRTMASICKEY
AND #{SEARCH_CONDITION}
AND EXISTS ( SELECT 1 FROM TWORK_MST_ASRT WHERE CTKEY = ASRT.CTKEY AND OWKEY = ASRT.OWKEY AND ASRTMASICKEY = ASRT.ASRTMASICKEY
#{item}
)
GROUP BY ASRT.CTKEY , CT.CTNM , ASRT.OWKEY , OW.OWNM , ASRT.ASRTMASICKEY , IC.ICNM

mapper.select:
/* wms-master-assort-sql-oracle.xml - selectAssortExcelList */ SELECT ASRT.CTKEY , CT.CTNM , ASRT.OWKEY , OW.OWNM , ASRT.ASRTMASICKEY , ICMS.ICNM AS ASRTMASICNM , ASRT.ASRTDTICKEY , IC.ICNM AS ASRTDTICNM , ASRT.QTY , ASRT.COLOR , ASRT.DESIGN , ASRT.CHRT , ASRT.INSERTDATE , ASRT.INSERTURKEY , ASRT.UPDATEDATE , ASRT.UPDATEURKEY FROM TWORK_MST_ASRT ASRT INNER JOIN TWORK_MST_CT CT ON CT.CTKEY = ASRT.CTKEY INNER JOIN TWORK_MST_OW OW ON OW.OWKEY = ASRT.OWKEY INNER JOIN TWORK_MST_IC ICMS ON ICMS.CTKEY = ASRT.CTKEY AND ICMS.OWKEY = ASRT.OWKEY AND ICMS.ICKEY = ASRT.ASRTMASICKEY INNER JOIN TWORK_MST_IC IC ON IC.CTKEY = ASRT.CTKEY AND IC.OWKEY = ASRT.OWKEY AND IC.ICKEY = ASRT.ASRTDTICKEY
AND #{SEARCH_CONDITION}
AND EXISTS ( SELECT 1 FROM TWORK_MST_ASRT WHERE CTKEY = ASRT.CTKEY AND OWKEY = ASRT.OWKEY AND ASRTMASICKEY = ASRT.ASRTMASICKEY
#{item}
)
ORDER BY ASRT.ASRTMASICKEY , ASRT.ASRTDTICKEY
